using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tipo de Provação de Gaia (apenas informativo/HUD — o comportamento real vem dos
/// <see cref="ChallengeDefinition.objectives"/> e <see cref="ChallengeDefinition.failConditions"/>
/// configurados). Serve para o pré-ecrã, o portal de entrada e para escolher
/// ícones/texto por defeito.
///
/// Para obter o nome de exibição em português, usar
/// <see cref="ChallengeDefinition.GetTypeName"/>.
/// </summary>
public enum ChallengeType
{
    Corrida,
    ColetaCronometrada,
    QuebraCabecaCronometrado,
    Combate,
    Sobrevivencia,
    DefesaDeNpc,
    ProvacaoDeApolo,
    Combinado,
}

/// <summary>
/// O que acontece ao player quando o desafio termina (sucesso OU falha):
///
/// - <see cref="PermanecerNoLocal"/>: o player continua onde está (desafios de
///   NPC e outros que acontecem "no meio do mundo normal" — confirmado pelo
///   utilizador para desafios de defesa de NPC/outros).
/// - <see cref="VoltarParaEntrada"/>: o player é teleportado para a posição de
///   entrada registada pelo activador (fora do portal) — usado por desafios de
///   Portal e pela Provação de Apolo.
/// </summary>
public enum ChallengeEndBehavior
{
    PermanecerNoLocal,
    VoltarParaEntrada,
}

/// <summary>
/// Entrada de "evento de NPC como recompensa": identifica o NPC e o evento a
/// disparar ao conceder a recompensa. Usado por <see cref="ChallengeReward.npcEventRewards"/>.
///
/// O NPC é encontrado em runtime via <see cref="NpcController.FindById"/> (registo
/// automático de NPCs activos). O evento é disparado via
/// <see cref="NpcController.TriggerEventById"/> — ignora condições e interacção
/// do player, permitindo cenas de libertação/animação automáticas.
/// </summary>
[System.Serializable]
public class NpcEventRewardEntry
{
    [Tooltip("NpcController.npcId do NPC que deve disparar o evento. Tem de estar na cena e activo quando a recompensa for concedida.")]
    public string npcId;

    [Tooltip("NpcEvent.eventId dentro desse NPC a disparar. Se o NPC já estiver a correr outro evento, este é ignorado (usar 'ActivateEventById' via Action no evento anterior em alternativa).")]
    public string npcEventId;
}

/// <summary>
/// Recompensa concedida por um <see cref="ChallengeDefinition"/> (itens,
/// Sementes, Runas de Gaia, e/ou eventos de NPC para cenas narrativas).
/// </summary>
[System.Serializable]
public class ChallengeReward
{
    [Tooltip("Itens concedidos ao receber esta recompensa (respeita ItemData.maxQuantity / savedAsCollected).")]
    public PickupLootEntry[] itemRewards;

    [Tooltip("Sementes concedidas (0 = nenhuma).")]
    [Min(0)] public int sementes = 0;

    [Tooltip("Runas de Gaia concedidas (0 = nenhuma).")]
    [Min(0)] public int runasDeGaia = 0;

    [Tooltip("Runas de Apolo concedidas (0 = nenhuma). Recompensa exclusiva da Provação de Apolo (isApoloTrial). Ao acumular 6 Runas de Apolo em PlayerProgress.runasDeApolo, o Emblema de Apolo é desbloqueado.")]
    [Min(0)] public int runasDeApolo = 0;

    [Tooltip("Eventos de NPC disparados após conceder os itens/recursos. Útil para cenas de libertação de animal, animação de NPC, ou qualquer mudança narrativa que exija mais do que sementes/runas/itens.\n\nCada entrada identifica um NPC por 'npcId' e um evento por 'npcEventId'. Os eventos são disparados em sequência (cada um inicia logo que o NPC o aceitar, sem aguardar conclusão do anterior).")]
    public NpcEventRewardEntry[] npcEventRewards;

    /// <summary>True se esta recompensa concede pelo menos alguma coisa.</summary>
    public bool HasAnything =>
        sementes > 0 || runasDeGaia > 0 || runasDeApolo > 0
        || (itemRewards != null && itemRewards.Length > 0)
        || (npcEventRewards != null && npcEventRewards.Length > 0);
}

/// <summary>
/// Melhor tempo registado para um desafio (PlayerProgress.challengeRecords —
/// Sistema de Missões/Desafios, Tarefa #13). Apenas relevante para desafios com
/// 'hasTimeLimit'.
/// </summary>
[System.Serializable]
public class ChallengeRecord
{
    public string challengeId;

    /// <summary>Melhor (menor) tempo de conclusão registado, em segundos.</summary>
    public float bestTimeSeconds;
}

/// <summary>
/// Uma fase (secção) da Provação de Apolo. Cada fase tem os seus próprios
/// objectivos, condições de falha, limite de tempo opcional e ponto de spawn
/// opcional para o player.
///
/// O <see cref="ChallengeManager"/> avança para a fase seguinte automaticamente
/// quando todos os objectivos "required" desta fase estão cumpridos. Se a fase
/// falhar (failCondition ou tempo esgotado), o <see cref="ChallengeManager"/>
/// trata como <see cref="ChallengeEndReason.Falha"/> do desafio todo (para a
/// Provação de Apolo com isApoloTrial = true, isso reinicia do início).
/// </summary>
[System.Serializable]
public class ApoloTrialPhase
{
    [Tooltip("Nome desta fase, mostrado no HUD (ex: 'Fase 1 — O Salto Infinito', 'Fase 3 — O Guardião'). Opcional.")]
    public string phaseName;

    [Tooltip("Se activo, esta fase tem o seu próprio limite de tempo (independente do 'timeLimitSeconds' do desafio raiz). Se o tempo desta fase esgotar, o desafio falha (e reinicia, se isApoloTrial).")]
    public bool hasTimeLimit = false;

    [Tooltip("Limite de tempo desta fase, em segundos (apenas se 'hasTimeLimit').")]
    [Min(1f)] public float timeLimitSeconds = 30f;

    [Tooltip("Objectivos que têm de ser cumpridos para avançar para a próxima fase. Todos os marcados como 'required' têm de estar completos.")]
    [SerializeReference] public List<ChallengeObjective> objectives = new List<ChallengeObjective>();

    [Tooltip("Condições de falha específicas desta fase. Se alguma for accionada, o desafio falha (e reinicia, se isApoloTrial).")]
    [SerializeReference] public List<ChallengeFailCondition> failConditions = new List<ChallengeFailCondition>();

    [Tooltip("Se definido, o player é teleportado para esta posição ao INICIAR esta fase. Útil para fases em zonas diferentes do mapa. Deixar vazio para permanecer onde está.")]
    public Transform phaseSpawnPoint;

    [Tooltip("Música tocada durante esta fase (substitui a música do desafio raiz enquanto esta fase estiver activa). Vazio = continua com a música do desafio.")]
    public UnityEngine.AudioClip phaseMusic;
}

/// <summary>
/// Define um Desafio/Missão Opcional (Sistema de Missões/Desafios): identidade,
/// objectivos, condições de falha, restrições, recompensas, HUD e áudio.
/// Não guarda estado próprio — todo o estado em runtime (timer, progresso,
/// activador actual, etc.) vive em <c>ChallengeManager</c>, tal como
/// <see cref="MissionData"/> não guarda estado (delegado em
/// <c>MissionManager</c>/<c>GameVariables</c>).
///
/// Ao iniciar, <c>ChallengeManager</c> define <see cref="ActiveVariable"/> = true
/// em GameVariables (e false ao terminar) — permite que o nível use
/// Condition_BoolVariable/Action_SetBoolVariable já existentes para, por
/// exemplo, fazer barreiras aparecerem enquanto o desafio estiver activo
/// (pedido do utilizador, Sistema de Missões/Desafios).
///
/// Ao completar com sucesso por PRIMEIRA vez, <c>ChallengeManager</c> também
/// define <see cref="CompletedVariable"/> = true (tal como
/// MissionData.CompletedVariable) — útil para condições de diálogo ("já
/// completaste este desafio?"), independentemente do registo em
/// PlayerProgress.completedChallengeIds (usado para a recompensa
/// única/ranking — Tarefa #13).
/// </summary>
[CreateAssetMenu(menuName = "Animals/Challenge Definition", fileName = "NewChallenge")]
public class ChallengeDefinition : ScriptableObject
{
    [Header("Identidade")]
    [Tooltip("Identificador único do desafio (usado para persistência, variáveis derivadas e ranking).")]
    public string challengeId;

    public string displayName;

    [TextArea] public string description;

    [Tooltip("Apenas informativo/HUD — o comportamento real é definido por \"Objectivos\" e \"Condições de Falha\" abaixo.")]
    public ChallengeType challengeType = ChallengeType.Combinado;

    [Tooltip("Ícone mostrado no pré-ecrã e no HUD do desafio (opcional).")]
    public Sprite icon;

    [Header("Restrições de Forma/Categoria")]
    [Tooltip("Categorias do GDD (Flags, combine várias) que podem iniciar este desafio. 'None' = sem restrição por categoria.")]
    public AnimalCategory allowedCategories = AnimalCategory.None;

    [Tooltip("Formas específicas adicionalmente permitidas (além de qualquer forma que tenha uma das 'allowedCategories'). Vazio = não adiciona formas extra.")]
    public List<AnimalFormData> allowedForms = new List<AnimalFormData>();

    [Header("Tempo")]
    [Tooltip("Se activo, o desafio falha automaticamente ao fim de 'timeLimitSeconds' (FailCondition_TimeExpired implícita). Necessário para activar as 'Restrições Durante o Desafio' abaixo.")]
    public bool hasTimeLimit = false;

    [Tooltip("Limite de tempo, em segundos (apenas se 'hasTimeLimit').")]
    [Min(0f)] public float timeLimitSeconds = 60f;

    [Header("Objectivos")]
    [Tooltip("Condições de vitória — todas as marcadas como \"obrigatório\" têm de estar cumpridas para o desafio ter sucesso.")]
    [SerializeReference] public List<ChallengeObjective> objectives = new List<ChallengeObjective>();

    [Header("Condições de Falha Adicionais")]
    [Tooltip("Além do tempo esgotado (se 'hasTimeLimit'): dano recebido, NPC defendido derrotado, variável específica, etc.")]
    [SerializeReference] public List<ChallengeFailCondition> failConditions = new List<ChallengeFailCondition>();

    [Header("Restrições Durante o Desafio")]
    [Tooltip("IMPORTANTE: só tem efeito se 'hasTimeLimit' estiver activo — garante que o jogador nunca fica permanentemente sem poder usar itens caso o desafio não seja resolvido (timeout sempre termina o desafio e restaura o uso normal). Se 'hasTimeLimit' estiver desligado, esta opção é ignorada pelo ChallengeManager (aviso no editor).")]
    public bool restrictItemUsage = false;

    [Tooltip("Habilidades primárias bloqueadas durante o desafio (botão de Habilidade não faz nada para estas). Mesma ressalva: só tem efeito se 'hasTimeLimit' estiver activo.")]
    public List<PrimaryAbility> restrictedAbilities = new List<PrimaryAbility>();

    [Tooltip("Se activo, o player não pode trocar de forma durante este desafio. Aplicado automaticamente pelo ChallengeTrigger quando 'requiredForm' está definido — o designer pode também activar manualmente em desafios onde trocar de animal quebraria a mecânica.")]
    public bool lockFormDuringChallenge = false;

    [Header("Variáveis Globais (GameVariables)")]
    [Tooltip("Nome da variável bool definida como TRUE enquanto o desafio está activo (e FALSE ao terminar — sucesso, falha ou abandono). Vazio = usa \"Desafio_<challengeId>_Ativo\". Útil para condicionar objectos no nível (ex: barreiras que bloqueiam fuga).")]
    public string activeVariableName = "";

    [Tooltip("Nome da variável bool definida como TRUE na primeira vez que o desafio é concluído com sucesso. Vazio = usa \"Desafio_<challengeId>_Concluido\".")]
    public string completedVariableName = "";

    [Header("Comportamento ao Terminar")]
    [Tooltip("PermanecerNoLocal: o player continua onde está (NPC/outros). VoltarParaEntrada: o player volta para a posição registada pelo activador, ex: fora do portal (Portal/Provação de Apolo).")]
    public ChallengeEndBehavior endBehavior = ChallengeEndBehavior.PermanecerNoLocal;

    [Header("Provação de Apolo")]
    [Tooltip("Se activo: morrer durante este desafio NÃO é tratada como morte normal (sem checkpoint/registo) — reinicia o desafio todo a partir do início, com vida cheia.")]
    public bool isApoloTrial = false;

    [Header("Recompensas")]
    [Tooltip("Recompensa concedida apenas na PRIMEIRA conclusão com sucesso.")]
    public ChallengeReward primaryReward;

    [Tooltip("Se activo, concede 'secondaryReward' em TODAS as conclusões com sucesso seguintes à primeira (repetições). Se inactivo, repetições não concedem nenhuma recompensa adicional.")]
    public bool hasSecondaryReward = false;

    [Tooltip("Recompensa concedida em cada repetição (apenas se 'hasSecondaryReward').")]
    public ChallengeReward secondaryReward;

    [Header("Áudio")]
    [Tooltip("Música tocada enquanto o desafio está activo (substitui a música da área).")]
    public AudioClip challengeMusic;

    [Tooltip("Música tocada no ecrã de SUCESSO (opcional — se vazio, mantém 'challengeMusic' até o fade terminar).")]
    public AudioClip successMusic;

    [Tooltip("Música tocada no ecrã de FALHA (opcional).")]
    public AudioClip failMusic;

    public AudioClip successSfx;
    public AudioClip failSfx;

    [Header("Provação de Apolo — Fases (isApoloTrial = true)")]
    [Tooltip("Fases da Provação de Apolo, executadas em sequência. Cada fase tem os seus próprios objectivos, condições de falha e limite de tempo.\n\nDeixar vazio para usar o sistema normal de objectivos (acima) — adequado para Provações simples ou outros desafios com isApoloTrial = true.\n\nQuando preenchido, os 'Objectivos' e 'Condições de Falha' do nível raiz são ignorados; cada fase usa os seus próprios.")]
    public List<ApoloTrialPhase> apoloPhases = new List<ApoloTrialPhase>();

    [Header("Integração com Área (Provação Opcional)")]
    [Tooltip("Se definida, o ChallengeManager marca automaticamente esta área como \"provação descoberta\" ao iniciar e \"provação concluída\" ao terminar com sucesso (PlayerProgress.MarkChallengeDiscovered/MarkChallengeCompleted) — usado pela % de conclusão da área e pela secção \"Área Atual\" (AreaData.hasOptionalChallenge). Deixar vazio se esta Provação de Gaia não corresponde ao desafio opcional de nenhuma área.")]
    public AreaData optionalChallengeArea;

    /// <summary>Nome efectivo da variável "provação activa" (derivado de challengeId se 'activeVariableName' estiver vazio).</summary>
    public string ActiveVariable => !string.IsNullOrEmpty(activeVariableName) ? activeVariableName : $"Provacao_{challengeId}_Ativa";

    /// <summary>Nome efectivo da variável "provação concluída" (derivado de challengeId se 'completedVariableName' estiver vazio).</summary>
    public string CompletedVariable => !string.IsNullOrEmpty(completedVariableName) ? completedVariableName : $"Provacao_{challengeId}_Concluida";

    /// <summary>
    /// Devolve o nome de exibição em português para cada tipo de Provação de Gaia
    /// — usado no portal de entrada, HUD e pré-ecrã.
    /// </summary>
    public static string GetTypeName(ChallengeType type) => type switch
    {
        ChallengeType.Corrida                  => "Corrida",
        ChallengeType.ColetaCronometrada       => "Coleta Cronometrada",
        ChallengeType.QuebraCabecaCronometrado => "Quebra-Cabeça",
        ChallengeType.Combate                  => "Combate",
        ChallengeType.Sobrevivencia            => "Sobrevivência",
        ChallengeType.DefesaDeNpc              => "Defesa de Aliado",
        ChallengeType.ProvacaoDeApolo          => "Provação de Apolo",
        ChallengeType.Combinado                => "Misto",
        _                                      => "Provação de Gaia",
    };

    /// <summary>Nome de exibição do tipo desta Provação de Gaia (ver <see cref="GetTypeName"/>).</summary>
    public string TypeDisplayName => GetTypeName(challengeType);

    /// <summary>
    /// True se a forma indicada pode iniciar esta Provação de Gaia: sem restrições
    /// configuradas (allowedCategories == None e allowedForms vazio), OU a
    /// forma está em 'allowedForms', OU partilha pelo menos uma categoria com
    /// 'allowedCategories'.
    /// </summary>
    public bool IsFormAllowed(AnimalFormData form)
    {
        bool noRestriction = allowedCategories == AnimalCategory.None && (allowedForms == null || allowedForms.Count == 0);
        if (noRestriction) return true;
        if (form == null) return false;

        if (allowedForms != null && allowedForms.Contains(form)) return true;

        return allowedCategories != AnimalCategory.None && (form.categories & allowedCategories) != 0;
    }
}
